div.script:
            (function () {
              var container = document.querySelector('.js_spoot_office_detail');
              if (!container) return;

              var officeId  = parseInt(container.dataset.officeId || '0');
              var pmRaw     = (container.dataset.pm || '0|0|0').split('|').map(parseFloat);
              var currency  = container.dataset.cur || '';
              var prices    = {morning: pmRaw[0], afternoon: pmRaw[1], full_day: pmRaw[2]};

              var dateHidden   = document.getElementById('spoot_date');
              var slotHidden   = document.getElementById('spoot_slot');
              var submitBtn    = document.getElementById('spoot_submit_btn');
              var grid         = document.getElementById('spoot-bk-grid');
              var monthTitle   = document.getElementById('spoot-bk-month-title');
              var slotsPanel   = document.getElementById('spoot-bk-slots');
              var summaryPanel = document.getElementById('spoot-bk-summary');
              var selDateEl    = document.getElementById('spoot-bk-sel-date');
              var summaryText  = document.getElementById('spoot-bk-summary-text');
              var summaryPrice = document.getElementById('spoot-bk-summary-price');
              var resetBtn     = document.getElementById('spoot-bk-reset-btn');
              var prevBtn      = document.getElementById('spoot-bk-prev');
              var nextBtn      = document.getElementById('spoot-bk-next');

              var radioPlan  = document.getElementById('radio_plan');
              var radioBold  = document.getElementById('radio_bold');
              var lblPlan    = document.getElementById('lbl_plan');
              var lblBold    = document.getElementById('lbl_bold');
              var costLabel  = document.getElementById('plan_cost_label');
              var warnEl     = document.getElementById('plan_balance_warn');
              var balanceEl  = document.getElementById('plan_balance_panel');
              var remaining  = parseFloat((balanceEl && balanceEl.dataset.remaining) || '9999');

              var MONTHS = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
              var SLOT_LABELS = {morning:'Mañana (8–12)', afternoon:'Tarde (14–18)', full_day:'Día completo (8–18)'};
              var SLOT_IDS = ['morning','afternoon','full_day'];

              var today = new Date(); today.setHours(0,0,0,0);
              var curYear  = today.getFullYear();
              var curMonth = today.getMonth();

              var monthData    = {};
              var selectedDate = null;
              var selectedSlot = null;

              function pad(n){ return n < 10 ? '0'+n : ''+n; }

              function fmtDate(ds) {
                var p = ds.split('-');
                return parseInt(p[2]) + ' de ' + MONTHS[parseInt(p[1])-1] + ' ' + p[0];
              }

              function makeEl(tag, cls, txt) {
                var el = document.createElement(tag);
                el.className = cls;
                if (txt !== undefined) el.textContent = txt;
                return el;
              }

              /* ── Fetch month data ──────────────────────────────────── */
              function fetchMonth(yr, mo1) {
                return fetch('/spoot/office/month-availability', {
                  method: 'POST',
                  headers: {'Content-Type': 'application/json'},
                  body: JSON.stringify({jsonrpc:'2.0', method:'call', id:1,
                    params:{office_id:officeId, year:yr, month:mo1}})
                }).then(function(r){ return r.json(); })
                  .then(function(d){ return d.result || []; });
              }

              function buildIndex(days) {
                monthData = {};
                days.forEach(function(d){ monthData[d.date] = d; });
              }

              /* ── Render calendar ───────────────────────────────────── */
              function renderCalendar() {
                var yr = curYear, mo0 = curMonth, mo1 = mo0 + 1;
                monthTitle.textContent = MONTHS[mo0] + ' ' + yr;

                var firstDow = new Date(yr, mo0, 1).getDay();
                firstDow = (firstDow + 6) % 7;
                var dim = new Date(yr, mo0 + 1, 0).getDate();

                grid.innerHTML = '';

                for (var i = 0; i < firstDow; i++) {
                  grid.appendChild(makeEl('div', 'spoot-bk-cell blank'));
                }

                for (var dn = 1; dn <= dim; dn++) {
                  var ds = yr + '-' + pad(mo1) + '-' + pad(dn);
                  var info = monthData[ds];
                  var cd = new Date(yr, mo0, dn); cd.setHours(0,0,0,0);
                  var isPast  = cd < today;
                  var isToday = cd.getTime() === today.getTime();

                  var cell = document.createElement('div');
                  cell.className = 'spoot-bk-cell';

                  var numCls = 'spoot-bk-num' + (isToday ? ' today-num' : '');
                  cell.appendChild(makeEl('span', numCls, dn));

                  if (isPast) {
                    cell.classList.add('past');
                  } else if (!info) {
                    cell.classList.add('loading');
                  } else if (info.blocked) {
                    cell.classList.add('blocked');
                    cell.title = info.block_reason || 'Bloqueado';
                    cell.appendChild(makeEl('span', 'spoot-bk-cell-lbl', info.block_reason || 'Bloqueado'));
                  } else if (!info.available.length) {
                    cell.classList.add('taken');
                    cell.appendChild(makeEl('span', 'spoot-bk-cell-lbl', 'Sin disponibilidad'));
                  } else {
                    cell.classList.add(info.available.length === 3 ? 'free' : 'partial');
                    var pips = document.createElement('div');
                    pips.className = 'spoot-bk-pips';
                    [{s:'morning',l:'M'},{s:'afternoon',l:'T'},{s:'full_day',l:'D'}].forEach(function(x){
                      pips.appendChild(makeEl('span','spoot-bk-pip '+(info.available.indexOf(x.s)>=0?'avail':'unavail'),x.l));
                    });
                    cell.appendChild(pips);
                    (function(d2, inf){ cell.addEventListener('click', function(){ onDayClick(d2, inf); }); })(ds, info);
                  }

                  if (ds === selectedDate) cell.classList.add('selected');
                  grid.appendChild(cell);
                }
              }

              /* ── Day click ─────────────────────────────────────────── */
              function onDayClick(ds, info) {
                selectedDate = ds;
                selectedSlot = null;
                dateHidden.value = '';
                slotHidden.value = '';
                submitBtn.disabled = true;

                selDateEl.textContent = fmtDate(ds);
                slotsPanel.classList.remove('d-none');
                summaryPanel.classList.add('d-none');

                SLOT_IDS.forEach(function(s){
                  var btn = document.getElementById('spoot-bk-btn-' + s);
                  if (!btn) return;
                  var avail = info.available.indexOf(s) >= 0;
                  btn.disabled = !avail;
                  btn.classList.toggle('unavail', !avail);
                  btn.classList.remove('active');
                });

                renderCalendar();
                slotsPanel.scrollIntoView({behavior:'smooth', block:'nearest'});
              }

              /* ── Slot click ────────────────────────────────────────── */
              function onSlotClick(slot) {
                if (!selectedDate) return;
                selectedSlot = slot;
                dateHidden.value = selectedDate;
                slotHidden.value = slot;

                SLOT_IDS.forEach(function(s){
                  var btn = document.getElementById('spoot-bk-btn-' + s);
                  if (btn) btn.classList.toggle('active', s === slot);
                });

                summaryText.textContent = fmtDate(selectedDate) + ' · ' + SLOT_LABELS[slot];
                var price = prices[slot];
                summaryPrice.textContent = price && price > 0 ? (currency + ' ' + Math.round(price).toLocaleString('es-CO')) : '';
                summaryPanel.classList.remove('d-none');

                submitBtn.disabled = false;
                updatePaymentUI();
                toggleDiscountSection();
              }

              /* ── Reset ─────────────────────────────────────────────── */
              function reset() {
                selectedDate = null; selectedSlot = null;
                dateHidden.value = ''; slotHidden.value = '';
                slotsPanel.classList.add('d-none');
                summaryPanel.classList.add('d-none');
                submitBtn.disabled = true;
                if (submitBtn) submitBtn.textContent = 'Confirmar reserva';
                renderCalendar();
              }

              /* ── Payment mode UI ───────────────────────────────────── */
              function slotCost(s){ return s === 'full_day' ? 1.0 : 0.5; }

              function updatePaymentUI() {
                if (!radioPlan) return;
                var slot   = slotHidden.value;
                var cost   = slotCost(slot);
                var isPlan = radioPlan.checked;

                if (costLabel) costLabel.textContent = slot
                  ? 'Descuenta ' + cost.toFixed(1) + ' día' + (cost === 1 ? '' : 's')
                  : 'Descuenta 0.5 ó 1 día';

                var insuf = isPlan && slot && remaining < cost;

                // Auto-switch to Bold when plan can't cover this slot
                if (insuf && radioBold) {
                  radioBold.checked = true;
                  isPlan = false;
                  insuf = false;
                  if (warnEl) {
                    warnEl.textContent = 'Saldo insuficiente — cambiado a pago con Bold.';
                    warnEl.classList.remove('d-none');
                    setTimeout(function(){ warnEl.classList.add('d-none'); }, 4000);
                  }
                } else {
                  if (warnEl) warnEl.classList.add('d-none');
                }

                if (lblPlan && lblBold) {
                  if (isPlan) {
                    lblPlan.style.border='2px solid #22c55e'; lblPlan.style.background='#f0fdf4';
                    lblBold.style.border='2px solid #e5e7eb'; lblBold.style.background='#f9fafb';
                  } else {
                    lblBold.style.border='2px solid #3b82f6'; lblBold.style.background='#eff6ff';
                    lblPlan.style.border='2px solid #e5e7eb'; lblPlan.style.background='#f9fafb';
                  }
                }

                if (submitBtn && selectedSlot) {
                  submitBtn.disabled = false;
                  submitBtn.textContent = isPlan ? 'Confirmar con mi plan' : 'Confirmar y pagar con Bold';
                }
              }

              /* ── Init: disable plan if no balance ──────────────────── */
              if (radioPlan && remaining < 0.5) {
                radioPlan.disabled = true;
                if (lblPlan) {
                  lblPlan.style.opacity = '0.45';
                  lblPlan.style.cursor = 'not-allowed';
                  var noBalLabel = lblPlan.querySelector('#plan_cost_label');
                  if (noBalLabel) noBalLabel.textContent = 'Sin días disponibles';
                }
                if (radioBold) radioBold.checked = true;
                updatePaymentUI();
              }

              /* ── Wire events ───────────────────────────────────────── */
              SLOT_IDS.forEach(function(s){
                var btn = document.getElementById('spoot-bk-btn-' + s);
                if (btn) btn.addEventListener('click', function(){ onSlotClick(s); });
              });

              if (resetBtn) resetBtn.addEventListener('click', reset);
              if (prevBtn)  prevBtn.addEventListener('click', function(){
                if (curMonth === 0){ curYear--; curMonth = 11; } else curMonth--;
                loadAndRender();
              });
              if (nextBtn)  nextBtn.addEventListener('click', function(){
                if (curMonth === 11){ curYear++; curMonth = 0; } else curMonth++;
                loadAndRender();
              });
              if (radioPlan) radioPlan.addEventListener('change', updatePaymentUI);
              if (radioBold) radioBold.addEventListener('change', updatePaymentUI);

              /* ── Código de descuento ──────────────────────────────── */
              var discountSection = document.getElementById('discount_section');
              var discountInput   = document.getElementById('discount_code_input');
              var discountApply   = document.getElementById('discount_apply_btn');
              var discountFeedback= document.getElementById('discount_feedback');

              // Mostrar sección cuando hay franja + modo Bold seleccionado
              function toggleDiscountSection() {
                if (!discountSection) return;
                var slot = slotHidden.value;
                var isBold = !radioPlan || !radioPlan.checked;
                discountSection.style.display = (slot && isBold) ? 'block' : 'none';
              }

              if (radioPlan) radioPlan.addEventListener('change', toggleDiscountSection);
              if (radioBold) radioBold.addEventListener('change', toggleDiscountSection);

              if (discountApply) {
                discountApply.addEventListener('click', function() {
                  var code = discountInput ? discountInput.value.trim().toUpperCase() : '';
                  var slot = slotHidden.value;
                  if (!code) return;
                  discountApply.disabled = true;
                  discountApply.textContent = '...';

                  fetch('/web/dataset/call_kw', {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({
                      jsonrpc: '2.0', method: 'call', id: 1,
                      params: {
                        model: 'office.discount',
                        method: 'search_read',
                        args: [],
                        kwargs: {}
                      }
                    })
                  });

                  // Llamada al endpoint propio
                  fetch('/spoot/discount/validate', {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({
                      jsonrpc: '2.0', method: 'call', id: 1,
                      params: { code: code, office_id: officeId, slot_type: slot }
                    })
                  })
                  .then(r => r.json())
                  .then(function(resp) {
                    discountApply.disabled = false;
                    discountApply.textContent = 'Aplicar';
                    var result = resp.result || {};
                    discountFeedback.style.display = 'block';
                    if (result.ok) {
                      discountFeedback.style.color = '#065f46';
                      discountFeedback.textContent = '✓ Descuento aplicado: ' + result.label
                        + ' → Total: ' + currency + ' ' + Math.round(result.final).toLocaleString('es-CO');
                      discountInput.readOnly = true;
                      discountApply.disabled = true;
                    } else {
                      discountFeedback.style.color = '#dc2626';
                      discountFeedback.textContent = '✗ ' + (result.error || 'Código no válido');
                    }
                  })
                  .catch(function() {
                    discountApply.disabled = false;
                    discountApply.textContent = 'Aplicar';
                    if (discountFeedback) {
                      discountFeedback.style.display = 'block';
                      discountFeedback.style.color = '#dc2626';
                      discountFeedback.textContent = 'Error al validar el código.';
                    }
                  });
                });
              }

              /* ── Init ──────────────────────────────────────────────── */
              function loadAndRender() {
                grid.innerHTML = '
Cargando…';
                fetchMonth(curYear, curMonth + 1)
                  .then(function(days){ buildIndex(days); renderCalendar(); })
                  .catch(function(){
                    grid.innerHTML = '
Error cargando disponibilidad';
                  });
              }

              loadAndRender();
            })();
